/* Aula 27 — modelJs: Notas (CRUD + storage + delegation) */

const form = document.querySelector('#form');
const tituloInput = document.querySelector('#titulo');
const conteudoInput = document.querySelector('#conteudo');
const erro = document.querySelector('#erro');
const lista = document.querySelector('#lista');

function save(key, value) {
  localStorage.setItem(key, JSON.stringify(value));
}

function load(key, fallback) {
  try {
    const raw = localStorage.getItem(key);
    if (raw === null) return fallback;
    return JSON.parse(raw);
  } catch {
    return fallback;
  }
}

let notas = load('notas', []);
let editingId = null;

function render() {
  lista.innerHTML = '';

  for (const n of notas) {
    const li = document.createElement('li');
    li.className = 'item';
    li.dataset.id = String(n.id);

    const box = document.createElement('div');
    box.className = 'stack';

    const strong = document.createElement('strong');
    strong.textContent = n.titulo;

    const preview = document.createElement('span');
    preview.className = 'muted';
    preview.textContent = (n.conteudo || '').slice(0, 60);

    box.append(strong, preview);

    const actions = document.createElement('div');

    const btnEdit = document.createElement('button');
    btnEdit.type = 'button';
    btnEdit.className = 'btn ghost edit';
    btnEdit.textContent = 'Editar';

    const btnDel = document.createElement('button');
    btnDel.type = 'button';
    btnDel.className = 'btn danger del';
    btnDel.textContent = 'Excluir';

    actions.append(btnEdit, btnDel);

    li.append(box, actions);
    lista.appendChild(li);
  }
}

function persistir() {
  save('notas', notas);
}

function addNota(titulo, conteudo) {
  notas.unshift({
    id: Date.now(),
    titulo,
    conteudo,
    updatedAt: Date.now()
  });
  persistir();
  render();
}

function updateNota(id, titulo, conteudo) {
  const n = notas.find(x => x.id === id);
  if (!n) return;
  n.titulo = titulo;
  n.conteudo = conteudo;
  n.updatedAt = Date.now();
  persistir();
  render();
}

function deleteNota(id) {
  notas = notas.filter(x => x.id !== id);
  persistir();
  render();
}

function entrarEdicao(id) {
  const n = notas.find(x => x.id === id);
  if (!n) return;

  tituloInput.value = n.titulo;
  conteudoInput.value = n.conteudo || '';
  editingId = id;

  const btn = form.querySelector('button[type="submit"]');
  if (btn) btn.textContent = 'Atualizar';
}

function sairEdicao() {
  editingId = null;
  form.reset();
  const btn = form.querySelector('button[type="submit"]');
  if (btn) btn.textContent = 'Salvar';
}

if (form && tituloInput && conteudoInput && erro && lista) {
  form.addEventListener('submit', (e) => {
    e.preventDefault();
    erro.textContent = '';

    const titulo = tituloInput.value.trim();
    const conteudo = conteudoInput.value.trim();

    if (!titulo) {
      erro.textContent = 'Título é obrigatório';
      return;
    }

    if (editingId) {
      updateNota(editingId, titulo, conteudo);
      sairEdicao();
      return;
    }

    addNota(titulo, conteudo);
    form.reset();
  });

  // delegation
  lista.addEventListener('click', (e) => {
    const item = e.target.closest('.item');
    if (!item) return;

    const id = Number(item.dataset.id);

    if (e.target.classList.contains('edit')) {
      entrarEdicao(id);
      return;
    }

    if (e.target.classList.contains('del')) {
      // se estiver editando essa nota, sai da edição
      if (editingId === id) sairEdicao();
      deleteNota(id);
      return;
    }
  });

  render();
}
